import{_ as a,o as e,c as s,a2 as r}from"./chunks/framework.CpJscuQM.js";const u=JSON.parse('{"title":"Ordinário da Missa","description":"","frontmatter":{},"headers":[],"relativePath":"ordinario.md","filePath":"ordinario.md"}'),n={name:"ordinario.md"};function i(d,o,p,t,c,m){return e(),s("div",null,[...o[0]||(o[0]=[r('<h1 id="ordinario-da-missa" tabindex="-1">Ordinário da Missa <a class="header-anchor" href="#ordinario-da-missa" aria-label="Permalink to &quot;Ordinário da Missa&quot;">​</a></h1><p>fonte: Missal Romano por meio do <a href="https://pocketterco.com.br/" target="_blank" rel="noreferrer">Pocket Terço</a></p><h2 id="ritos-iniciais" tabindex="-1">Ritos Iniciais <a class="header-anchor" href="#ritos-iniciais" aria-label="Permalink to &quot;Ritos Iniciais&quot;">​</a></h2><ol><li><span class="ordinario-rubrica"> Reunido o povo, o sacerdote dirige-se com os ministros ao altar, enquanto se executa o canto de entrada. Chegando ao altar, faz com os ministros uma profunda inclinação, beija o altar em sinal de veneração e, se for oportuno, incensa a cruz e o altar. Depois se dirige com os ministros à cadeira. Terminado o canto de entrada, o sacerdote e os fiéis, todos de pé, fazem o sinal da cruz, enquanto o sacerdote, voltado para o povo, diz: </span></li></ol><p><strong>Em nome do Pai e do Filho e do Espírito Santo.</strong></p><span class="ordinario-rubrica"> O povo responde: </span><p><strong>Amém.</strong></p><ol start="2"><li><span class="ordinario-rubrica">Em seguida, o sacerdote, abrindo os braços, saúda o povo com uma das seguintes fórmulas: <br> a) </span><em>A graça de nosso Senhor Jesus Cristo, o amor do Pai e a comunhão do Espírito Santo estejam convosco.</em><br><span class="ordinario-rubrica"> (Cf. 2Cor 13, 13)</span></li></ol><details class="details custom-block"><summary>Abrir outras saudações</summary><p><span class="ordinario-rubrica">b)</span> A graça e a paz de Deus, nosso Pai, e de Jesus Cristo, nosso Senhor, estejam convosco. <br><span class="ordinario-rubrica">(Cf. 1Cor 1, 3)</span></p><p><span class="ordinario-rubrica">c)</span> Ⓑ O Senhor, que encaminha os nossos corações para o amor de Deus e a constância de Cristo, esteja convosco. <br><span class="ordinario-rubrica">(2Ts 3, 5)</span></p><p><span class="ordinario-rubrica">d)</span> Ⓑ O Deus da esperança, que nos cumula de toda alegria e paz em nossa fé, pela ação do Espírito Santo, esteja convosco. <br><span class="ordinario-rubrica">(Rm 15, 13)</span></p><p><span class="ordinario-rubrica">e)</span> Ⓑ A vós, irmãos, paz e fé da parte de Deus, o Pai, e do Senhor Jesus Cristo. <br><span class="ordinario-rubrica">(Ef 6, 23)</span></p><p><span class="ordinario-rubrica">f)</span> Ⓑ Irmãos eleitos segundo a presciência de Deus Pai, pela santificação do Espírito para obedecer a Jesus Cristo e participar da bênção da aspersão do seu sangue, graça e paz vos sejam concedidas abundantemente. <br><span class="ordinario-rubrica">(1Pd 1, 1-2)</span></p><p><span class="ordinario-rubrica">g)</span> Ⓑ A graça e a paz daquele que é, que era e que vem, estejam convosco. <br><span class="ordinario-rubrica">(Ap 1, 8)</span></p></details><p><span class="ordinario-rubrica">O povo responde:</span><br><strong>Bendito seja Deus, que nos reuniu no amor de Cristo.</strong></p><p><span class="ordinario-rubrica">Ou, o sacerdote, abrindo os braços, diz:<br> h) </span><em>O Senhor esteja convosco.</em></p><p><span class="ordinario-rubrica">O povo responde:</span><br><strong>Ele está no meio de nós.</strong></p><details class="details custom-block"><summary>Abrir opção para missa com Bispo</summary><p><span class="ordinario-rubrica">O Bispo, nesta primeira saudação, em vez de</span> O Senhor esteja convosco, <span class="ordinario-rubrica">diz:</span><br><em>A paz esteja convosco.</em></p><p><span class="ordinario-rubrica">E o povo responde:</span><br><strong>Bendito seja Deus, Que nos reuniu no amor de Cristo.</strong></p></details><ol start="3"><li>O sacerdote, diácono ou outro ministro poderá, com brevíssimas palavras, introduzir os fiéis na Missa do dia.</li></ol><h2 id="ato-penitencial" tabindex="-1">Ato Penitencial <a class="header-anchor" href="#ato-penitencial" aria-label="Permalink to &quot;Ato Penitencial&quot;">​</a></h2><p><span class="ordinario-rubrica">Aos domingos, especialmente no tempo pascal, no lugar do Ato Penitencial habitual pode-se fazer a bênção e a aspersão da água em memória do Batismo como no Apêndice II do Missal Romano. Neste caso, após a conclusão, seguem-se as invocações Senhor, tende piedade de nós (Kýrie, eléison).</span></p><details class="details custom-block"><summary>Abrir primeira fórmula</summary><h3 id="primeira-formula" tabindex="-1">Primeira fórmula <a class="header-anchor" href="#primeira-formula" aria-label="Permalink to &quot;Primeira fórmula&quot;">​</a></h3><ol start="4"><li><span class="ordinario-rubrica">O sacerdote convida os fiéis ao ato penitencial:</span></li></ol><p><em>Irmãos e irmãs, reconheçamos os nossos pecados, para celebrarmos dignamente os santos mistérios.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ O Senhor Jesus, que nos convida à mesa da Palavra e da Eucaristia, nos chama a segui-lo fielmente. Reconheçamos ser pecadores e invoquemos com confiança a misericórdia do Pai.</em></p><p><span class="ordinario-rubrica">Ou, especialmente aos domingos e durante a oitava de Páscoa:</span></p><p><em>Ⓑ No dia em que celebramos a vitória de Cristo sobre o pecado e a morte, também nós somos convidados a morrer para o pecado e ressurgir para uma vida nova. Reconheçamo-nos necessitados da misericórdia do Pai.</em></p><p><span class="ordinario-rubrica">Após um momento de silêncio, usa-se a seguinte fórmula. O sacerdote diz:</span></p><p><em>Confessemos os nossos pecados:</em></p><p><span class="ordinario-rubrica">Todos:</span></p><p><strong>Confesso a Deus todo-poderoso e a vós, irmãos e irmãs, que pequei muitas vezes por pensamentos e palavras, atos e omissões,</strong></p><p><span class="ordinario-rubrica">e, batendo no peito, dizem:</span></p><p><strong>por minha culpa, minha culpa, minha tão grande culpa.</strong></p><p><span class="ordinario-rubrica">Em seguida, continuam:</span></p><p><strong>E peço à Virgem Maria, aos Anjos e Santos e a vós, irmãos e irmãs, que rogueis por mim a Deus, nosso Senhor.</strong></p><p><span class="ordinario-rubrica">Segue-se a absolvição sacerdotal:</span></p><p><em>Deus todo-poderoso tenha compaixão de nós, perdoe os nossos pecados e nos conduza à vida eterna.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Amém.</strong></p></details><details class="details custom-block"><summary>Abrir segunda fórmula</summary><h3 id="segunda-formula" tabindex="-1">Segunda fórmula <a class="header-anchor" href="#segunda-formula" aria-label="Permalink to &quot;Segunda fórmula&quot;">​</a></h3><ol start="5"><li><span class="ordinario-rubrica">O sacerdote convida os fiéis ao ato penitencial:</span></li></ol><p><em>Irmãos e irmãs, reconheçamos os nossos pecados, para celebrarmos dignamente os santos mistérios.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ No início desta celebração eucarística, peçamos a conversão do coração, fonte de reconciliação e comunhão com Deus e com os irmãos e irmãs.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ De coração contrito e humilde, aproximemo-nos do Deus justo e santo, para que tenha piedade de nós, pecadores.</em></p><p><span class="ordinario-rubrica">Após um momento de silêncio, o sacerdote diz:</span></p><p><em>Tende compaixão de nós, Senhor.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>Porque somos pecadores.</strong></p><p><span class="ordinario-rubrica">O sacerdote:</span></p><p><em>Manifestai, Senhor, a vossa misericórdia.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>E dai-nos a vossa salvação.</strong></p><p><span class="ordinario-rubrica">Segue-se a absolvição sacerdotal:</span></p><p><em>Deus todo-poderoso tenha compaixão de nós, perdoe os nossos pecados e nos conduza à vida eterna.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Amém.</strong></p></details><details class="details custom-block"><summary>Abrir terceira fórmula</summary><h3 id="terceira-formula" tabindex="-1">Terceira fórmula <a class="header-anchor" href="#terceira-formula" aria-label="Permalink to &quot;Terceira fórmula&quot;">​</a></h3><ol start="6"><li><span class="ordinario-rubrica">O sacerdote convida os fiéis ao ato penitencial:</span></li></ol><p><em>Irmãos e irmãs, reconheçamos os nossos pecados, para celebrarmos dignamente os santos mistérios.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Em Jesus Cristo, o Justo, que intercede por nós e nos reconcilia com o Pai, abramos o nosso espírito ao arrependimento para sermos dignos de nos aproximar da mesa do Senhor.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ O Senhor disse: &quot;Quem dentre vós estiver sem pecado, atire a primeira pedra&quot;. Reconheçamo-nos todos pecadores e perdoemo-nos mutuamente do fundo do coração.</em></p><p><span class="ordinario-rubrica">Após um momento de silêncio, o sacerdote, o diácono ou outro ministro propõe as seguintes invocações ou outras semelhantes com Senhor, tende piedade de nós.</span></p><p><span class="ordinario-rubrica">Ⓑ Para o canto se pode usar a aclamação grega: Kýrie, eléison.</span></p><p><em>Senhor, que viestes salvar os corações arrependidos, tende piedade de nós.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Senhor, tende piedade de nós.</strong></p><p><span class="ordinario-rubrica">O sacerdote:</span></p><p><em>Cristo, que viestes chamar os pecadores, tende piedade de nós.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>Cristo, tende piedade de nós.</strong></p><p><span class="ordinario-rubrica">O sacerdote:</span></p><p><em>Senhor, que intercedeis por nós junto do Pai, tende piedade de nós.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>Senhor, tende piedade de nós.</strong></p><p><span class="ordinario-rubrica">Segue-se a absolvição sacerdotal:</span></p><p><em>Deus todo-poderoso tenha compaixão de nós, perdoe os nossos pecados e nos conduza à vida eterna.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Amém.</strong></p></details><details class="details custom-block"><summary>Abrir invocações alternativas para os diversos tempos</summary><h3 id="invocacoes-alternativas-para-os-diversos-tempos" tabindex="-1">Invocações alternativas para os diversos tempos <a class="header-anchor" href="#invocacoes-alternativas-para-os-diversos-tempos" aria-label="Permalink to &quot;Invocações alternativas para os diversos tempos&quot;">​</a></h3><h4 id="tempo-comum" tabindex="-1">Tempo Comum <a class="header-anchor" href="#tempo-comum" aria-label="Permalink to &quot;Tempo Comum&quot;">​</a></h4><ol><li><em>Senhor, que sois o caminho que leva ao Pai, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que sois a verdade que ilumina os povos, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que sois a vida que renova o mundo, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="2"><li><em>Senhor, que oferecestes o vosso perdão a Pedro arrependido, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que prometestes o paraíso ao bom ladrão, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que acolheis toda pessoa que confia na vossa misericórdia, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="3"><li><em>Senhor, que viestes, não para condenar, mas para perdoar, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que vos alegrais pelo pecador arrependido, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que muito perdoais a quem muito ama, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="4"><li><em>Senhor, que viestes procurar quem estava perdido, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que viestes dar a vida em resgate de muitos, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que congregais na unidade os filhos de Deus dispersos, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="5"><li><em>Senhor, que sois a plenitude da verdade e da graça, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que vos tornastes pobre para nos enriquecer, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que viestes para fazer de nós o vosso povo santo, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><h4 id="tempo-do-advento" tabindex="-1">Tempo do Advento <a class="header-anchor" href="#tempo-do-advento" aria-label="Permalink to &quot;Tempo do Advento&quot;">​</a></h4><ol><li><em>Senhor, que viestes ao mundo para nos salvar, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que continuamente nos visitais com a graça do vosso Espírito, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que vireis um dia para julgar as nossas obras, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="2"><li><em>Senhor, que sois o defensor dos pobres, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que sois o refúgio dos fracos, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que sois a esperança dos pecadores, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="3"><li><em>Senhor, que vindes visitar vosso povo na paz, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que vindes salvar o que estava perdido, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que vindes criar um mundo novo, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><h4 id="tempo-do-natal" tabindex="-1">Tempo do Natal <a class="header-anchor" href="#tempo-do-natal" aria-label="Permalink to &quot;Tempo do Natal&quot;">​</a></h4><ol><li><em>Senhor, Filho de Deus, que, nascendo da Virgem Maria, vos fizestes nosso irmão, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, Filho do homem, que conheceis e compreendeis nossa fraqueza, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, Filho primogênito do Pai, que fazeis de nós uma só família, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="2"><li><em>Senhor, rei da paz, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, luz nas trevas, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, imagem do homem novo, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><h4 id="tempo-da-quaresma" tabindex="-1">Tempo da Quaresma <a class="header-anchor" href="#tempo-da-quaresma" aria-label="Permalink to &quot;Tempo da Quaresma&quot;">​</a></h4><ol><li><em>Senhor que na cruz perdoastes o ladrão arrependido, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que nos mandastes perdoar-nos mutuamente antes de nos aproximar do vosso altar, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que confiastes à vossa Igreja o ministério da reconciliação, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="2"><li><em>Senhor, que na água e no Espírito nos regenerastes à vossa imagem, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que enviais o vosso Espírito para criar em nós um coração novo, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que nos tornastes participantes do vosso Corpo e do vosso Sangue, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="3"><li><em>Senhor, que fazeis passar da morte para a vida quem ouve a vossa palavra, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que quisestes ser levantado da terra para que tenha a vida eterna todo aquele que crê em vós, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que nos submeteis ao julgamento da vossa cruz, para levar-nos à glória da ressurreição, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><h4 id="tempo-da-pascoa" tabindex="-1">Tempo da Páscoa <a class="header-anchor" href="#tempo-da-pascoa" aria-label="Permalink to &quot;Tempo da Páscoa&quot;">​</a></h4><ol><li><em>Senhor, nossa paz, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, nossa Páscoa, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, nossa vida, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="2"><li><em>Senhor, que sois o eterno sacerdote da nova Aliança, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que nos edificais como pedras vivas no templo santo de Deus, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que nos tornais concidadãos dos santos no reino dos céus, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="3"><li><em>Senhor, que, subindo ao céu, nos presenteastes com o dom do Espírito, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que dais vida a todas as coisas com o poder da vossa palavra, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, Rei do universo e Senhor dos séculos, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="4"><li><em>Senhor, que, subindo ao céu, vos tornastes Rei do universo, e Senhor dos séculos, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que na vossa ascensão levastes cativo o cativeiro, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que voltando à casa do Pai abristes o céu para nós, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p><ol start="5"><li><em>Senhor, que pelo Espírito Santo estais presente no mundo, tende piedade de nós.</em></li></ol><p><strong>℟. Senhor, tende piedade de nós.</strong></p><p><em>Cristo, que dais o Espírito Santo para o perdão dos pecados, tende piedade de nós.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong></p><p><em>Senhor, que enviais o Espírito Santo para criar um mundo novo, tende piedade de nós.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong></p></details><h2 id="senhor-tende-piedade" tabindex="-1">Senhor, tende piedade <a class="header-anchor" href="#senhor-tende-piedade" aria-label="Permalink to &quot;Senhor, tende piedade&quot;">​</a></h2><ol start="7"><li><span class="ordinario-rubrica">Seguem-se as invocações Senhor, tende piedade de nós (Kýrie, eléison), caso já não tenham ocorrido no ato penitencial:</span></li></ol><p><em>Senhor, tende piedade de nós.</em><span class="ordinario-rubrica">Ou:</span><em>Kýrie, eléison.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong><span class="ordinario-rubrica">Ou:</span><strong>℟. Kýrie, eléison.</strong></p><p><em>Cristo, tende piedade de nós.</em><span class="ordinario-rubrica">Ou:</span><em>Christe, eléison.</em></p><p><strong>℟. Cristo, tende piedade de nós.</strong><span class="ordinario-rubrica">Ou:</span><strong>℟. Christe, eléison.</strong></p><p><em>Senhor, tende piedade de nós.</em><span class="ordinario-rubrica">Ou:</span><em>Kýrie, eléison.</em></p><p><strong>℟. Senhor, tende piedade de nós.</strong><span class="ordinario-rubrica">Ou:</span><strong>℟. Kýrie, eléison.</strong></p><h2 id="gloria" tabindex="-1">Glória <a class="header-anchor" href="#gloria" aria-label="Permalink to &quot;Glória&quot;">​</a></h2><ol start="8"><li><span class="ordinario-rubrica">Quando for prescrito, canta-se ou recita-se em seguida o hino:</span></li></ol><p><strong>Glória a Deus nas alturas, e paz na terra aos homens por Ele amados. Senhor Deus, rei dos céus, Deus Pai todo-poderoso. Nós vos louvamos, nós vos bendizemos, nós vos adoramos, nós vos glorificamos, nós vos damos graças por vossa imensa glória. Senhor Jesus Cristo, Filho Unigênito, Senhor Deus, Cordeiro de Deus, Filho de Deus Pai. Vós que tirais o pecado do mundo, tende piedade de nós. Vós que tirais o pecado do mundo, acolhei a nossa súplica. Vós que estais à direita do Pai, tende piedade de nós. Só Vós sois o Santo, só vós, o Senhor, só vós, o Altíssimo, Jesus Cristo, com o Espírito Santo, na glória de Deus Pai. Amém.</strong></p><h2 id="oracao-coleta" tabindex="-1">Oração Coleta <a class="header-anchor" href="#oracao-coleta" aria-label="Permalink to &quot;Oração Coleta&quot;">​</a></h2><ol start="9"><li><span class="ordinario-rubrica">Terminado o hino, de mãos unidas, o sacerdote diz:</span></li></ol><p><em>Oremos.</em></p><p><span class="ordinario-rubrica">E todos oram com o sacerdote, por algum tempo, em silêncio. Então o sacerdote, de braços abertos, profere a oração Coleta; ao terminar, o povo aclama:</span></p><p><strong>Amém.</strong></p><h2 id="liturgia-da-palavra" tabindex="-1">Liturgia da Palavra <a class="header-anchor" href="#liturgia-da-palavra" aria-label="Permalink to &quot;Liturgia da Palavra&quot;">​</a></h2><ol start="10"><li><span class="ordinario-rubrica">O leitor dirige-se ao ambão e proclama a primeira leitura, que todos ouvem sentados. Para indicar o fim da leitura, o leitor aclama:</span></li></ol><p><em>Palavra do Senhor.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Graças a Deus.</strong></p><p><span class="ordinario-rubrica">Após as leituras, é aconselhável um momento de silêncio para meditação.</span></p><ol start="11"><li><p><span class="ordinario-rubrica">O salmista ou o cantor canta ou recita o salmo, e o povo, o refrão.</span></p></li><li><p><span class="ordinario-rubrica">Se houver uma segunda leitura, o leitor a proclama do ambão, como descrito acima. Para indicar o fim da leitura, o leitor aclama:</span></p></li></ol><p><em>Palavra do Senhor.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Graças a Deus.</strong></p><ol start="13"><li><p><span class="ordinario-rubrica">Segue-se o Aleluia ou outro canto estabelecido pelas rubricas, conforme o tempo litúrgico exige.</span></p></li><li><p><span class="ordinario-rubrica">Enquanto isso, o sacerdote, quando se usa incenso, coloca-o no turíbulo. O diácono, que vai proclamar o Evangelho, inclinando-se profundamente diante do sacerdote, pede a bênção em voz baixa:</span></p></li></ol><p><em>Dá-me a tua bênção.</em></p><p><span class="ordinario-rubrica">O sacerdote diz em voz baixa:</span></p><p><em>O Senhor esteja em teu coração e em teus lábios para que possas anunciar dignamente o seu Evangelho: em nome do Pai e do Filho ✠ e do Espírito Santo.</em></p><p><span class="ordinario-rubrica">O diácono faz o sinal da cruz e responde:</span></p><p><strong>Amém.</strong></p><p><span class="ordinario-rubrica">Se não houver diácono, o sacerdote, inclinado diante do altar, reza em silêncio:</span></p><p><em>Ó Deus todo-poderoso, purificai-me o coração e os lábios, para que eu possa anunciar dignamente o vosso santo Evangelho.</em></p><ol start="15"><li><span class="ordinario-rubrica">O diácono ou o sacerdote dirige-se ao ambão, acompanhado, se for oportuno, pelos ministros com o incenso e velas, e diz:</span></li></ol><p><em>O Senhor esteja convosco.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Ele está no meio de nós.</strong></p><p><span class="ordinario-rubrica">O diácono ou o sacerdote diz:</span></p><p><em>Proclamação do Evangelho de Jesus Cristo, segundo N.</em></p><p><span class="ordinario-rubrica">E, enquanto isso, faz o sinal da cruz sobre o livro e, depois, sobre si mesmo, na fronte, na boca e no peito.</span></p><p><span class="ordinario-rubrica">O povo aclama:</span></p><p><strong>Glória a vós, Senhor.</strong></p><p><span class="ordinario-rubrica">Então o diácono ou o sacerdote, se for o caso, incensa o livro, e proclama o Evangelho.</span></p><ol start="16"><li><span class="ordinario-rubrica">Terminado o Evangelho, o diácono ou o sacerdote aclama:</span></li></ol><p><em>Palavra da Salvação.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Glória a vós, Senhor.</strong></p><p><span class="ordinario-rubrica">Depois beija o livro, dizendo em silêncio:</span></p><p><em>Pelas palavras do santo Evangelho sejam perdoados os nossos pecados.</em></p><ol start="17"><li><p><span class="ordinario-rubrica">Em seguida, faz-se a homilia, que compete ao sacerdote ou diácono; ela é obrigatória em todos domingos e festas de preceito e recomendada também nos outros dias.</span></p></li><li><p><span class="ordinario-rubrica">Terminada a homilia, quando prescrito, canta-se ou recita-se o símbolo ou profissão de fé.</span></p></li></ol><details class="details custom-block"><summary>Abrir Símbolo Niceno-constantinopolitano</summary><h3 id="simbolo-niceno-constantinopolitano" tabindex="-1">Símbolo Niceno-constantinopolitano <a class="header-anchor" href="#simbolo-niceno-constantinopolitano" aria-label="Permalink to &quot;Símbolo Niceno-constantinopolitano&quot;">​</a></h3><p><strong>Creio em um só Deus, Pai todo-poderoso, Criador do céu e da terra, de todas as coisas visíveis e invisíveis. Creio em um só Senhor, Jesus Cristo, Filho Unigênito de Deus, nascido do Pai antes de todos os séculos: Deus de Deus, luz da luz, Deus verdadeiro de Deus verdadeiro, gerado, não criado, consubstancial ao Pai. Por ele todas as coisas foram feitas. E por nós, homens, e para nossa salvação, desceu dos céus.</strong></p><p><span class="ordinario-rubrica">Às palavras seguintes, até e se fez homem, todos se inclinam.</span></p><p><strong>E se encarnou pelo Espírito Santo, no seio da Virgem Maria, e se fez homem. Também por nós foi crucificado sob Pôncio Pilatos; padeceu e foi sepultado. Ressuscitou ao terceiro dia, conforme as Escrituras, e subiu aos céus, onde está sentado à direita do Pai. E de novo há de vir, em sua glória, para julgar os vivos e os mortos; e o seu reino não terá fim. Creio no Espírito Santo, Senhor que dá a vida, e procede do Pai e do Filho; e com o Pai e o Filho é adorado e glorificado: ele que falou pelos profetas. Creio na Igreja, una, santa, católica e apostólica. Professo um só batismo para remissão dos pecados. E espero a ressurreição dos mortos e a vida do mundo que há de vir. Amém.</strong></p></details><details class="details custom-block"><summary>Abrir Símbolo dos Apóstolos</summary><h3 id="simbolo-dos-apostolos" tabindex="-1">Símbolo dos Apóstolos <a class="header-anchor" href="#simbolo-dos-apostolos" aria-label="Permalink to &quot;Símbolo dos Apóstolos&quot;">​</a></h3><ol start="19"><li><span class="ordinario-rubrica">No lugar do símbolo niceno-constantinopolitano, pode-se usar, sobretudo nos tempos da Quaresma e da Páscoa, a profissão de fé batismal da Igreja Romana, o assim chamado Símbolo dos Apóstolos:</span></li></ol><p><strong>Creio em Deus Pai todo-poderoso, Criador do céu e da terra. E em Jesus Cristo, seu único Filho, nosso Senhor.</strong></p><p><span class="ordinario-rubrica">Às palavras seguintes, até Virgem Maria, todos se inclinam.</span></p><p><strong>Que foi concebido pelo poder do Espírito Santo, nasceu da Virgem Maria, padeceu sob Pôncio Pilatos, foi crucificado, morto e sepultado, desceu à mansão dos mortos, ressuscitou ao terceiro dia, subiu aos céus, está sentado à direita de Deus Pai todo-poderoso, donde há de vir a julgar os vivos e os mortos. Creio no Espírito Santo, na Santa Igreja católica, na comunhão dos santos, na remissão dos pecados, na ressurreição da carne e na vida eterna. Amém.</strong></p></details><ol start="20"><li><span class="ordinario-rubrica">Em seguida, faz-se a oração universal ou dos fiéis.</span></li></ol><h2 id="liturgia-eucaristica" tabindex="-1">Liturgia Eucarística <a class="header-anchor" href="#liturgia-eucaristica" aria-label="Permalink to &quot;Liturgia Eucarística&quot;">​</a></h2><ol start="21"><li><p><span class="ordinario-rubrica">Inicia-se o canto da preparação das oferendas, enquanto os ministros colocam no altar o corporal, o sanguinho, o cálice, a pala e o Missal.</span></p></li><li><p><span class="ordinario-rubrica">Convém que os fiéis expressem sua participação trazendo uma oferenda: pão e vinho para a celebração da Eucaristia, ou outro donativo para auxílio da comunidade e dos pobres.</span></p></li><li><p><span class="ordinario-rubrica">O sacerdote, de pé junto ao altar, recebe a patena com o pão em suas mãos e, levantando-a um pouco sobre o altar, diz em silêncio:</span></p></li></ol><p><em>Bendito sejais, Senhor, Deus do universo, pelo pão que recebemos de vossa bondade, fruto da terra e do trabalho humano, que agora vos apresentamos, e para nós se vai tornar pão da vida.</em></p><p><span class="ordinario-rubrica">Em seguida, coloca a patena com o pão sobre o corporal. Se o canto da preparação das oferendas não continuar, o sacerdote pode recitar em voz alta as palavras acima, e o povo acrescenta:</span></p><p><strong>Bendito seja Deus para sempre!</strong></p><ol start="24"><li><span class="ordinario-rubrica">O diácono ou o sacerdote coloca o vinho e um pouco de água no cálice, rezando em silêncio:</span></li></ol><p><em>Pelo mistério desta água e deste vinho possamos participar da divindade do vosso Filho, que se dignou assumir a nossa humanidade.</em></p><ol start="25"><li><span class="ordinario-rubrica">Em seguida, o sacerdote recebe o cálice em suas mãos e, elevando-o um pouco sobre o altar, diz em silêncio:</span></li></ol><p><em>Bendito sejais, Senhor, Deus do universo, pelo vinho que recebemos de vossa bondade, fruto da videira e do trabalho humano, que agora vos apresentamos, e que para nós se vai tornar vinho da salvação.</em></p><p><span class="ordinario-rubrica">Coloca o cálice sobre o corporal. Se o canto da preparação das oferendas não continuar, o sacerdote pode recitar em voz alta as palavras acima, e o povo acrescenta:</span></p><p><strong>Bendito seja Deus para sempre!</strong></p><ol start="26"><li><span class="ordinario-rubrica">Em seguida o sacerdote, profundamente inclinado, reza em silêncio:</span></li></ol><p><em>De coração contrito e humilde, sejamos, Senhor, acolhidos por vós; e seja o nosso sacrifício de tal modo oferecido que vos agrade, Senhor, nosso Deus.</em></p><ol start="27"><li><p><span class="ordinario-rubrica">E, se for oportuno, incensa as oferendas, a cruz e o altar. Depois, o diácono ou outro ministro incensa o sacerdote e o povo.</span></p></li><li><p><span class="ordinario-rubrica">Em seguida, o sacerdote, de pé ao lado do altar, lava as mãos, dizendo em silêncio:</span></p></li></ol><p><em>Lavai-me, Senhor, de minhas faltas e purificai-me do meu pecado.</em></p><ol start="29"><li><span class="ordinario-rubrica">Estando, depois, no meio do altar e voltado para o povo, o sacerdote estende e une as mãos e diz:</span></li></ol><p><em>Orai, irmãos e irmãs, para que o meu e o vosso sacrifício seja aceito por Deus Pai todo-poderoso.</em></p><details class="details custom-block"><summary>Abrir outras opções</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Orai, irmãos e irmãs, para que esta nossa família, reunida em nome de Cristo, possa oferecer um sacrifício que seja aceito por Deus Pai todo-poderoso.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Orai, irmãos e irmãs, para que, trazendo ao altar as alegrias e fadigas de cada dia, nos disponhamos a oferecer um sacrifício aceito por Deus Pai todo-poderoso.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Orai, irmãos e irmãs, para que o sacrifício da Igreja, nesta pausa restauradora na caminhada rumo ao céu, seja aceito por Deus Pai todo-poderoso.</em></p></details><p><span class="ordinario-rubrica">O povo se levanta e responde:</span></p><p><strong>Receba o Senhor por tuas mãos este sacrifício, para glória do seu nome, para nosso bem e de toda a sua santa Igreja.</strong></p><ol start="30"><li><span class="ordinario-rubrica">Em seguida, abrindo os braços, o sacerdote profere a oração sobre as oferendas; ao terminar, o povo aclama:</span></li></ol><p><strong>Amém.</strong></p><h2 id="oracao-eucaristica" tabindex="-1">Oração Eucarística <a class="header-anchor" href="#oracao-eucaristica" aria-label="Permalink to &quot;Oração Eucarística&quot;">​</a></h2><ol start="31"><li><span class="ordinario-rubrica">Começando a Oração Eucarística, o sacerdote abre os braços e diz ou canta:</span></li></ol><p><em>O Senhor esteja convosco.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Ele está no meio de nós.</strong></p><p><span class="ordinario-rubrica">Erguendo as mãos, o sacerdote prossegue:</span></p><p><em>Corações ao alto.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>O nosso coração está em Deus.</strong></p><p><span class="ordinario-rubrica">O sacerdote, com os braços abertos, acrescenta:</span></p><p><em>Demos graças ao Senhor, nosso Deus.</em></p><p><span class="ordinario-rubrica">O povo:</span></p><p><strong>É nosso dever e nossa salvação.</strong></p><p><span class="ordinario-rubrica">O sacerdote, de braços abertos, reza ou canta o Prefácio. Ao final, une as mãos e, com o povo, conclui o Prefácio cantando ou dizendo:</span></p><p><strong>Santo, Santo, Santo, Senhor, Deus do universo. O céu e a terra proclamam a vossa glória. Hosana nas alturas! Bendito o que vem em nome do Senhor! Hosana nas alturas!</strong></p><ol start="32"><li><span class="ordinario-rubrica">Em todas as Missas, o sacerdote pode cantar as partes mais importantes da Oração Eucarística. Na primeira Oração Eucarística, ou Cânon Romano, pode-se omitir o que está entre parênteses.</span></li></ol><h2 id="rito-da-comunhao" tabindex="-1">Rito da Comunhão <a class="header-anchor" href="#rito-da-comunhao" aria-label="Permalink to &quot;Rito da Comunhão&quot;">​</a></h2><ol start="124"><li><span class="ordinario-rubrica">Tendo colocado o cálice e a patena sobre o altar, o sacerdote diz, de mãos unidas:</span></li></ol><p><em>Obedientes à palavra do Salvador e formados por seu divino ensinamento, ousamos dizer:</em></p><details class="details custom-block"><summary>Abrir outras monições</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Rezemos, com amor e confiança, a oração que o Senhor Jesus nos ensinou:</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Somos chamados filhos de Deus e realmente o somos; por isso, podemos rezar confiantes:</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ O Senhor nos comunicou o seu Espírito. Com a confiança e a liberdade de filhos e filhas, digamos juntos:</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ O banquete da Eucaristia é sinal de reconciliação e vínculo de união fraterna. Unidos como irmãos e irmãs, rezemos, juntos, como o Senhor nos ensinou:</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Guiados pelo Espírito de Jesus e iluminados pela sabedoria do Evangelho, ousamos dizer:</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Guiados pelo Espírito Santo, que ora em nós e por nós, elevemos as mãos ao Pai e rezemos juntos a oração que o próprio Jesus nos ensinou:</em></p></details><p><span class="ordinario-rubrica">O sacerdote abre os braços e prossegue com o povo:</span></p><p><strong>Pai nosso que estais nos céus, santificado seja o vosso nome; venha a nós o vosso reino, seja feita a vossa vontade, assim na terra como no céu. O pão nosso de cada dia nos dai hoje; perdoai-nos as nossas ofensas, assim como nós perdoamos a quem nos tem ofendido; e não nos deixeis cair em tentação, mas livrai-nos do mal.</strong></p><ol start="125"><li><span class="ordinario-rubrica">O sacerdote prossegue sozinho, de braços abertos:</span></li></ol><p><em>Livrai-nos de todos os males, ó Pai, e dai-nos hoje a vossa paz. Ajudados pela vossa misericórdia, sejamos sempre livres do pecado e protegidos de todos os perigos, enquanto aguardamos a feliz esperança e a vinda do nosso Salvador, Jesus Cristo.</em></p><p><span class="ordinario-rubrica">O sacerdote une as mãos. O povo conclui a oração, aclamando:</span></p><p><strong>Vosso é o reino, o poder e a glória para sempre.</strong></p><ol start="126"><li><span class="ordinario-rubrica">O sacerdote, de braços abertos, diz em voz alta:</span></li></ol><p><em>Senhor Jesus Cristo, dissestes aos vossos Apóstolos: eu vos deixo a paz, eu vos dou a minha paz. Não olheis os nossos pecados, mas a fé que anima vossa Igreja; dai-lhe, segundo o vosso desejo, a paz e a unidade. Vós, que sois Deus, com o Pai e o Espírito Santo.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Amém.</strong></p><ol start="127"><li><span class="ordinario-rubrica">O sacerdote, voltado para o povo, estendendo e unindo as mãos, acrescenta:</span></li></ol><p><em>A paz do Senhor esteja sempre convosco.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>O amor de Cristo nos uniu.</strong></p><ol start="128"><li><span class="ordinario-rubrica">Em seguida, se for oportuno, o diácono ou o sacerdote diz:</span></li></ol><p><em>Irmãos e irmãs, saudai-vos em Cristo Jesus.</em></p><details class="details custom-block"><summary>Abrir outras opções</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Como filhos e filhas do Deus da paz, saudai-vos com um gesto de comunhão fraterna.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Em Jesus, que nos tornou todos irmãos e irmãs, saudai-vos com um sinal de reconciliação e de paz.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ No Espírito de Cristo ressuscitado, saudai-vos com um sinal de paz.</em></p></details><p><span class="ordinario-rubrica">E todos, segundo o costume do lugar, manifestam uns aos outros a paz, a comunhão e a caridade.</span></p><ol start="129"><li><span class="ordinario-rubrica">Em seguida, o sacerdote parte o pão consagrado sobre a patena e coloca um pedaço no cálice, rezando em silêncio:</span></li></ol><p><em>Esta união do Corpo e do Sangue de Jesus, o Cristo e Senhor nosso, que vamos receber, nos faça participar da vida eterna.</em></p><ol start="130"><li><span class="ordinario-rubrica">Enquanto isso, canta-se ou recita-se:</span></li></ol><p><strong>Cordeiro de Deus, que tirais o pecado do mundo, tende piedade de nós. Cordeiro de Deus, que tirais o pecado do mundo, tende piedade de nós. Cordeiro de Deus, que tirais o pecado do mundo, dai-nos a paz.</strong></p><p><span class="ordinario-rubrica">Essas palavras podem ser repetidas ainda mais vezes, se a fração do pão se prolongar; na última vez, porém, diz-se: dai-nos a paz.</span></p><ol start="131"><li><span class="ordinario-rubrica">O sacerdote, de mãos unidas, reza em silêncio:</span></li></ol><p><em>Senhor Jesus Cristo, Filho do Deus vivo, que, cumprindo a vontade do Pai e agindo com o Espírito Santo, pela vossa morte destes vida ao mundo, livrai-me por este vosso santíssimo Corpo e Sangue dos meus pecados e de todo mal; dai-me cumprir sempre a vossa vontade e jamais separar-me de vós.</em></p><details class="details custom-block"><summary>Abrir outra oração antes da comunhão</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Senhor Jesus Cristo, o vosso Corpo e o vosso Sangue, que vou receber, não se tornem causa de juízo e condenação; mas, por vossa bondade, sejam proteção e remédio para minha vida.</em></p></details><ol start="132"><li><span class="ordinario-rubrica">O sacerdote faz genuflexão, toma a hóstia e, elevando-a um pouco sobre a patena ou sobre o cálice, diz em voz alta, voltado para o povo:</span></li></ol><p><em>Felizes os convidados para a Ceia do Senhor.</em></p><details class="details custom-block"><summary>Abrir outras opções</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Quem come minha carne e bebe meu sangue permanece em mim e eu nele.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Provai e vede como o Senhor é bom; feliz de quem nele encontra seu refúgio.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Eu sou o Pão vivo, que desceu do céu; se alguém come deste Pão, viverá eternamente.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ⓑ Felizes os convidados para o banquete nupcial do Cordeiro.</em></p></details><p><span class="ordinario-rubrica">O sacerdote acrescenta, com o povo, uma só vez:</span></p><p><strong>Senhor, eu não sou digno(a) de que entreis em minha morada, mas dizei uma palavra e serei salvo(a).</strong></p><ol start="133"><li><span class="ordinario-rubrica">O sacerdote, voltado para o altar, reza em silêncio e comunga o Corpo e o Sangue de Cristo.</span></li></ol><p><em>O Corpo de Cristo me guarde para a vida eterna.</em></p><p><em>O Sangue de Cristo me guarde para a vida eterna.</em></p><ol start="134"><li><span class="ordinario-rubrica">Em seguida, aproxima-se dos que vão comungar e mostra a hóstia um pouco elevada a cada um deles, dizendo:</span></li></ol><p><em>O Corpo de Cristo.</em></p><p><span class="ordinario-rubrica">O que vai comungar responde:</span></p><p><strong>Amém.</strong></p><p><span class="ordinario-rubrica">E comunga. O diácono ou o ministro extraordinário da distribuição da sagrada Comunhão procede do mesmo modo.</span></p><ol start="135"><li><p><span class="ordinario-rubrica">Se houver Comunhão sob as duas espécies, observa-se o rito prescrito na Instrução Geral sobre o Missal Romano.</span></p></li><li><p><span class="ordinario-rubrica">Enquanto o sacerdote comunga o Corpo de Cristo, inicia-se o canto da comunhão.</span></p></li><li><p><span class="ordinario-rubrica">Terminada a Comunhão, o sacerdote, o diácono ou acólito purifica a patena e o cálice. Enquanto se faz a purificação, o sacerdote reza em silêncio:</span></p></li></ol><p><em>Fazei, Senhor, que conservemos num coração puro o que a nossa boca recebeu. E que esta dádiva temporal se transforme para nós em remédio eterno.</em></p><ol start="138"><li><p><span class="ordinario-rubrica">Então o sacerdote pode voltar à cadeira. É aconselhável guardar algum tempo de silêncio sagrado ou proferir um salmo ou cântico de louvor.</span></p></li><li><p><span class="ordinario-rubrica">Em seguida, junto ao altar ou à cadeira, o sacerdote, de pé, voltado para o povo, diz de mãos unidas:</span></p></li></ol><p><em>Oremos.</em></p><p><span class="ordinario-rubrica">Todos rezam algum tempo em silêncio, se ainda não o fizeram. Em seguida, o sacerdote profere a oração Depois da comunhão. Ao terminar, o povo aclama:</span></p><p><strong>Amém.</strong></p><h2 id="ritos-finais" tabindex="-1">Ritos Finais <a class="header-anchor" href="#ritos-finais" aria-label="Permalink to &quot;Ritos Finais&quot;">​</a></h2><ol start="140"><li><p><span class="ordinario-rubrica">Se necessário, fazem-se breves comunicações ao povo.</span></p></li><li><p><span class="ordinario-rubrica">Em seguida, faz-se a despedida. O sacerdote, voltado para o povo, abre os braços e diz:</span></p></li></ol><p><em>O Senhor esteja convosco.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Ele está no meio de nós.</strong></p><p><span class="ordinario-rubrica">O sacerdote abençoa o povo, dizendo:</span></p><p><em>Abençoe-vos Deus todo-poderoso, Pai e Filho ✠ e Espírito Santo.</em></p><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Amém.</strong></p><ol start="142"><li><span class="ordinario-rubrica">Em alguns dias ou ocasiões, esta fórmula de bênção pode ser precedida, de acordo com as rubricas, por outra fórmula mais solene ou pela oração sobre o povo.</span></li></ol><details class="details custom-block"><summary>Abrir opção na Missa pontifical</summary><ol start="143"><li><span class="ordinario-rubrica">Na Missa pontifical, o celebrante recebe a mitra e, estendendo as mãos, diz:</span></li></ol><p><em>O Senhor esteja convosco.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Ele está no meio de nós.</strong></p><p><span class="ordinario-rubrica">O celebrante diz:</span></p><p><em>Bendito seja o nome do Senhor.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Agora e para sempre.</strong></p><p><span class="ordinario-rubrica">O celebrante diz:</span></p><p><em>Nossa proteção está no nome do Senhor.</em></p><p><span class="ordinario-rubrica">Todos respondem:</span></p><p><strong>Que fez o céu e a terra.</strong></p><p><span class="ordinario-rubrica">Então o celebrante recebe o báculo, se o utilizar, e diz a bênção fazendo três vezes o sinal da cruz sobre o povo:</span></p><p><em>Abençoe-vos Deus todo-poderoso, Pai ✠ e Filho ✠ e Espírito ✠ Santo.</em></p><p><span class="ordinario-rubrica">Todos:</span></p><p><strong>Amém.</strong></p></details><ol start="144"><li><span class="ordinario-rubrica">Depois, o diácono ou o próprio sacerdote diz ao povo, de mãos unidas:</span></li></ol><p><em>Ide em paz, e o Senhor vos acompanhe.</em></p><details class="details custom-block"><summary>Abrir outras despedidas</summary><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ide em paz, e anunciai o Evangelho do Senhor.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Ide em paz, e glorificai o Senhor com vossa vida.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>Em nome do Senhor, ide em paz e o Senhor vos acompanhe.</em></p><p><span class="ordinario-rubrica">Ou:</span></p><p><em>A alegria do Senhor seja a vossa força; ide em paz e o Senhor vos acompanhe.</em></p></details><p><span class="ordinario-rubrica">O povo responde:</span></p><p><strong>Graças a Deus.</strong></p><ol start="145"><li><p><span class="ordinario-rubrica">Então o sacerdote beija o altar em sinal de veneração, como no início. Feita com os ministros a devida reverência, retira-se.</span></p></li><li><p><span class="ordinario-rubrica">Caso ocorra ainda alguma ação litúrgica, omite-se o rito de despedida.</span></p></li></ol><details class="details custom-block"><summary>Abrir nota sobre bênçãos solenes</summary><p><span class="ordinario-rubrica">As bênçãos solenes e orações sobre o povo podem ser usadas no fim da celebração conforme o tempo litúrgico, o sacramento celebrado ou outras circunstâncias pastorais indicadas pelo Missal Romano.</span></p></details>',179)])])}const b=a(n,[["render",i]]);export{u as __pageData,b as default};
